import { Navigate } from 'react-router-dom'



function SingOut() {

	function exitAcc(){
		localStorage.setItem("userName", "")
		return <Navigate to="/" replace/>
	}

	return (
		<>
			<button id="singOutBtn" onClick={exitAcc}>SingOut</button>
		</>
	);
}

export default SingOut;
